// Объединяем все переводы
for (var lang in extraLangs) {
    translations[lang] = extraLangs[lang];
}

// Добавляем остальные языки (ca, ms, fa, uz, ar, id, hu, iw, hi, kk, zh) — базовые копии английского с заменой названий
var simpleLangs = ['ca', 'ms', 'fa', 'uz', 'ar', 'id', 'hu', 'iw', 'hi', 'kk', 'zh'];
for (var i = 0; i < simpleLangs.length; i++) {
    var l = simpleLangs[i];
    if (!translations[l]) {
        translations[l] = JSON.parse(JSON.stringify(translations.en));
        translations[l].app_name = 'Kukumber Messenger';
        if (l === 'ca') translations[l].tagline = 'Comunicació fresca cada dia 🥒';
        else if (l === 'ms') translations[l].tagline = 'Komunikasi segar setiap hari 🥒';
        else if (l === 'fa') translations[l].tagline = 'ارتباط تازه هر روز 🥒';
        else if (l === 'uz') translations[l].tagline = 'Har kuni yangi muloqot 🥒';
        else if (l === 'ar') translations[l].tagline = 'تواصل منعش كل يوم 🥒';
        else if (l === 'id') translations[l].tagline = 'Komunikasi segar setiap hari 🥒';
        else if (l === 'hu') translations[l].tagline = 'Friss kommunikáció minden nap 🥒';
        else if (l === 'iw') translations[l].tagline = 'תקשורת רעננה כל יום 🥒';
        else if (l === 'hi') translations[l].tagline = 'हर दिन ताज़ा संचार 🥒';
        else if (l === 'kk') translations[l].tagline = 'Күн сайын жаңа қарым-қатынас 🥒';
        else if (l === 'zh') translations[l].tagline = '每天新鲜沟通 🥒';
    }
}

var currentLanguage = localStorage.getItem('kukumber_language') || 'ru';

function applyTranslations() {
    var t = translations[currentLanguage];
    if (!t) return;
    // Настройки
    var settingsHeader = document.querySelector('#settings-tab .settings-header h2');
    if (settingsHeader) settingsHeader.textContent = t.settings;
    var navChats = document.querySelector('#nav-chats .nav-label');
    var navReels = document.querySelector('#nav-reels .nav-label');
    var navSettings = document.querySelector('#nav-settings .nav-label');
    if (navChats) navChats.textContent = t.chats;
    if (navReels) navReels.textContent = t.reels;
    if (navSettings) navSettings.textContent = t.settings;
    var searchInput = document.querySelector('#search-chats');
    if (searchInput) searchInput.placeholder = t.search_placeholder;
    var chatBtns = document.querySelectorAll('.create-buttons .btn-create span:last-child');
    if (chatBtns[0]) chatBtns[0].textContent = t.new_chat;
    if (chatBtns[1]) chatBtns[1].textContent = t.new_group;
    if (chatBtns[2]) chatBtns[2].textContent = t.new_channel;
    if (chatBtns[3]) chatBtns[3].textContent = t.find_users;
    var noChat = document.querySelector('#no-chat-selected h2');
    if (noChat) noChat.textContent = t.select_chat;
    var messageInput = document.querySelector('#message-input');
    if (messageInput) messageInput.placeholder = t.message_placeholder;
    var sendBtn = document.querySelector('.btn-send');
    if (sendBtn) sendBtn.title = t.send;
    var reelsHeader = document.querySelector('#reels-tab .reels-header h2');
    if (reelsHeader) reelsHeader.textContent = t.reels;
    var reelTabs = document.querySelectorAll('#reels-tab .reel-tab-btn');
    if (reelTabs[0]) reelTabs[0].textContent = t.feed;
    if (reelTabs[1]) reelTabs[1].textContent = t.my_reels;
    if (reelTabs[2]) reelTabs[2].textContent = t.liked_reels;
    var createReelBtn = document.querySelector('.btn-create-reel');
    if (createReelBtn) createReelBtn.textContent = '+ ' + t.create_reel;
    var newChatHeader = document.querySelector('#new-chat-modal .modal-header h3');
    if (newChatHeader) newChatHeader.textContent = t.new_chat;
    var createGroupHeader = document.querySelector('#create-group-modal .modal-header h3');
    if (createGroupHeader) createGroupHeader.textContent = t.create_group;
    var groupNameInput = document.querySelector('#group-name');
    if (groupNameInput) groupNameInput.placeholder = t.group_name;
    var groupDescInput = document.querySelector('#group-description');
    if (groupDescInput) groupDescInput.placeholder = t.description;
    var createChannelHeader = document.querySelector('#create-channel-modal .modal-header h3');
    if (createChannelHeader) createChannelHeader.textContent = t.create_channel;
    var channelNameInput = document.querySelector('#channel-name');
    if (channelNameInput) channelNameInput.placeholder = t.channel_name;
    var channelDescInput = document.querySelector('#channel-description');
    if (channelDescInput) channelDescInput.placeholder = t.description;
    var publicLabel = document.querySelector('.channel-type-options label:first-child');
    var privateLabel = document.querySelector('.channel-type-options label:last-child');
    if (publicLabel) publicLabel.innerHTML = '🌍 ' + t.public;
    if (privateLabel) privateLabel.innerHTML = '🔒 ' + t.private;
    var channelLinkInput = document.querySelector('#channel-link');
    if (channelLinkInput) channelLinkInput.placeholder = t.channel_link;
    var nextBtn = document.querySelector('#group-step-1 .btn-primary');
    if (nextBtn && nextBtn.textContent === 'Далее') nextBtn.textContent = t.next;
    var backBtn = document.querySelector('#group-step-2 .btn-secondary');
    if (backBtn && backBtn.textContent === 'Назад') backBtn.textContent = t.back;
    var createGroupBtn = document.querySelector('#group-step-2 .btn-primary');
    if (createGroupBtn && createGroupBtn.textContent === 'Создать') createGroupBtn.textContent = t.create_group;
    var createChannelBtn = document.querySelector('#create-channel-modal .btn-primary');
    if (createChannelBtn && createChannelBtn.textContent === 'Создать') createChannelBtn.textContent = t.create_channel;
    var publishReelBtn = document.querySelector('#create-reel-modal .btn-primary');
    if (publishReelBtn && publishReelBtn.textContent === 'Опубликовать') publishReelBtn.textContent = t.publish;
    var reelCaptionInput = document.querySelector('#reel-caption');
    if (reelCaptionInput) reelCaptionInput.placeholder = t.reel_caption;
    var allowCommentsLabel = document.querySelector('#reel-comments-enabled + label');
    if (allowCommentsLabel) allowCommentsLabel.textContent = t.allow_comments;
    var menuItems = document.querySelectorAll('#settings-tab .settings-section .settings-item');
    var menuLabels = [t.notifications, t.privacy, t.theme, t.language, t.storage, t.about, t.help, t.logout];
    for (var i = 0; i < menuItems.length && i < menuLabels.length; i++) {
        var span = menuItems[i].querySelector('span:nth-child(2)');
        if (span && i !== 0) span.textContent = menuLabels[i];
    }
    var footer = document.querySelector('#settings-tab .settings-footer');
    if (footer) {
        var firstP = footer.querySelector('p:first-child');
        var lastP = footer.querySelector('p:last-child');
        if (firstP) firstP.textContent = t.app_name;
        if (lastP) lastP.textContent = t.tagline;
    }
    var logoutItem = document.querySelector('#settings-tab .settings-item.danger span:nth-child(2)');
    if (logoutItem) logoutItem.textContent = t.logout;
}

function showLanguageSettings() {
    var langCodes = {
        ru: 'Русский', en: 'English', es: 'Español', de: 'Deutsch', it: 'Italiano',
        fr: 'Français', be: 'Беларуская', uk: 'Українська', pl: 'Polski', ko: '한국어',
        nl: 'Nederlands', pt_br: 'Português (Brasil)', ca: 'Català', ms: 'Bahasa Melayu',
        tr: 'Türkçe', fa: 'فارسی', uz: 'Oʻzbekcha', ar: 'العربية', id: 'Bahasa Indonesia',
        hu: 'Magyar', iw: 'עברית', hi: 'हिन्दी', kk: 'Қазақша', zh: '中文'
    };
    var langList = '';
    for (var code in langCodes) {
        var isSelected = (code === currentLanguage);
        langList += '<div class="user-item" onclick="setLanguage(\'' + code + '\')" style="justify-content:space-between; cursor:pointer;">' +
            '<span>' + (isSelected ? '✓ ' : '') + langCodes[code] + '</span>' +
            '<span style="color:var(--forest);">' + (isSelected ? '✓' : '→') + '</span>' +
        '</div>';
    }
    var oldModal = document.getElementById('temp-language-modal');
    if (oldModal) oldModal.remove();
    var modal = document.createElement('div');
    modal.className = 'modal';
    modal.id = 'temp-language-modal';
    modal.innerHTML = '<div class="modal-content">' +
        '<div class="modal-header"><h3>' + (translations[currentLanguage]?.select_language || 'Выберите язык') + '</h3><button onclick="closeLanguageModal()" class="btn-close">×</button></div>' +
        '<div class="users-list" style="max-height:70vh;">' + langList + '</div>' +
    '</div>';
    document.body.appendChild(modal);
    modal.classList.remove('hidden');
}

function closeLanguageModal() {
    var modal = document.getElementById('temp-language-modal');
    if (modal) modal.remove();
}

function setLanguage(langCode) {
    if (translations[langCode]) {
        currentLanguage = langCode;
        localStorage.setItem('kukumber_language', langCode);
        showNotification(translations[langCode]?.settings_saved || 'Language changed', 'success');
        closeLanguageModal();
        applyTranslations();
        updateModalTexts();
    }
}

function updateModalTexts() {
    var t = translations[currentLanguage];
    if (!t) return;
    var editProfileTitle = document.querySelector('#edit-profile-modal .modal-header h3');
    if (editProfileTitle) editProfileTitle.textContent = t.edit_profile;
    var editUsername = document.getElementById('edit-username');
    if (editUsername) editUsername.placeholder = t.username;
    var editBio = document.getElementById('edit-bio');
    if (editBio) editBio.placeholder = t.about_me;
    var saveBtn = document.querySelector('#edit-profile-modal .btn-primary');
    if (saveBtn) saveBtn.textContent = t.save;
}

function showEditProfileModal() {
    var t = translations[currentLanguage];
    document.getElementById('edit-profile-modal').classList.remove('hidden');
    document.getElementById('edit-username').value = currentUserData?.username || '';
    document.getElementById('edit-bio').value = currentUserData?.bio || '';
    var preview = document.getElementById('edit-avatar-preview');
    if (currentUserData?.avatar) {
        preview.style.backgroundImage = 'url(' + currentUserData.avatar + ')';
        preview.style.backgroundSize = 'cover';
        preview.textContent = '';
    } else {
        preview.style.backgroundImage = '';
        preview.textContent = '🥒';
    }
    var header = document.querySelector('#edit-profile-modal .modal-header h3');
    if (header) header.textContent = t.edit_profile;
    var usernameInput = document.getElementById('edit-username');
    if (usernameInput) usernameInput.placeholder = t.username;
    var bioInput = document.getElementById('edit-bio');
    if (bioInput) bioInput.placeholder = t.about_me;
    var saveBtn = document.querySelector('#edit-profile-modal .btn-primary');
    if (saveBtn) saveBtn.textContent = t.save;
}

function closeEditProfileModal() { document.getElementById('edit-profile-modal').classList.add('hidden'); }
function previewEditAvatar(event) {
    var file = event.target.files[0];
    if (file) {
        var reader = new FileReader();
        reader.onload = function(e) {
            var preview = document.getElementById('edit-avatar-preview');
            preview.style.backgroundImage = 'url(' + e.target.result + ')';
            preview.style.backgroundSize = 'cover';
            preview.textContent = '';
        };
        reader.readAsDataURL(file);
        window.pendingAvatarFile = file;
    }
}
function saveProfile() {
    var t = translations[currentLanguage];
    var newUsername = document.getElementById('edit-username').value.trim();
    if (!newUsername) { showNotification(t.enter_username, 'error'); return; }
    var newBio = document.getElementById('edit-bio').value.trim();
    var updates = { username: newUsername, bio: newBio };
    function saveData(avatarUrl) {
        if (avatarUrl) updates.avatar = avatarUrl;
        database.ref('users/' + currentUser.uid).update(updates).then(function() {
            closeEditProfileModal();
            showNotification(t.profile_updated, 'success');
            if (typeof updateUserDisplay === 'function') updateUserDisplay();
        }).catch(function(err) { showNotification('Error', 'error'); });
    }
    if (window.pendingAvatarFile) {
        uploadImageToImgBB(window.pendingAvatarFile).then(function(data) {
            window.pendingAvatarFile = null;
            saveData(data.url);
        }).catch(function() { saveData(null); });
    } else { saveData(null); }
}
function showNotificationSettings() { var t = translations[currentLanguage]; showNotification(t.notifications + ': ' + t.in_development, 'info'); }
function showPrivacySettings() { var t = translations[currentLanguage]; showNotification(t.privacy + ': ' + t.in_development, 'info'); }
function showThemeSettings() { var t = translations[currentLanguage]; showNotification(t.theme + ': ' + t.in_development, 'info'); }
function showStorageSettings() { var t = translations[currentLanguage]; showNotification(t.storage + ': ' + t.in_development, 'info'); }
function showAbout() { var t = translations[currentLanguage]; alert(t.app_name + ' ' + (t.version || 'v1.0') + '\n\n' + (t.tagline || 'Свежее общение каждый день 🥒')); }
function showHelp() { var t = translations[currentLanguage]; showNotification(t.help + ': ' + t.in_development, 'info'); }

function detectUserLanguage() {
    var saved = localStorage.getItem('kukumber_language');
    if (saved && translations[saved]) { currentLanguage = saved; }
    else {
        var browserLang = (navigator.language || 'ru').substring(0,2).toLowerCase();
        var supported = ['ru','en','es','de','it','fr','be','uk','pl','ko','nl','pt_br','ca','ms','tr','fa','uz','ar','id','hu','iw','hi','kk','zh'];
        if (supported.indexOf(browserLang) !== -1 && translations[browserLang]) currentLanguage = browserLang;
        else currentLanguage = 'ru';
        localStorage.setItem('kukumber_language', currentLanguage);
    }
    applyTranslations();
}
detectUserLanguage();
